class Solution {
    public int minSwaps(int[] nums) {
        int n = nums.length;
        int numOnes = 0;
        for (int num : nums) {
            if (num == 1) {
                numOnes++;
            }
        }
        if (numOnes == 0 || numOnes == n) {
            return 0;
        }
        int swaps = 0;
        int lastOneIndex = -1;
        for (int i = 0; i < n; i++) {
            if (nums[i] == 1) {
                if (lastOneIndex == -1) {
                    lastOneIndex = i;
                } else {
                    swaps++;
                    lastOneIndex = i;
                }
            }
        }
        return swaps;
    }
}
